#include<cstdio>
#include<cmath>
#include<algorithm>
using namespace std;int sx[99],sy[99],n;int lz0,lz1,lzy;double gy(int lx){for(int i=0;i<n-1;i++)if(lx>=sx[i]&&(lx<sx[i+1]||i==n-2))return sy[i]+(double)(sy[i+1]-sy[i])*(lx-sx[i])/(sx[i+1]-sx[i]);return sy[n-1];}int main(){scanf("%d",&n);for(int i=0;i<n;i++)scanf("%d%d",&sx[i],&sy[i]);for(int i=0;i<n-1;i++)if(sy[i]==sy[i+1]&&sx[i+1]-sx[i]>=1000){lz0=sx[i];lz1=sx[i+1];lzy=sy[i];break;}for(;;){int X,Y,hs,vs,fu,ro,pw;scanf("%d%d%d%d%d%d%d",&X,&Y,&hs,&vs,&fu,&ro,&pw);double tx=(lz0+lz1)/2.0,dg=Y-gy(X),df=Y-lzy;int tr=0,tp=0;if(dg<150&&vs<-20){tr=0;tp=4;}else if(Y>300&&(abs(hs)>25||X<lz0||X>lz1)){if(hs>60)tr=90;else if(hs<-60)tr=-90;else if(X<lz0&&hs<10)tr=-45;else if(X>lz1&&hs>-10)tr=45;else if(abs(hs)>20)tr=hs>0?30:-30;else tr=X<tx-100?-10:X>tx+100?10:0;tp=4;}else if(df<300&&X>=lz0&&X<=lz1&&abs(hs)<=25){tr=0;tp=vs<-40?4:vs<-20?3:vs<-10?2:0;}else{tr=abs(hs)>5?(hs>0?10:-10):X<tx-50?-5:X>tx+50?5:0;tp=tr?4:vs<-35?4:vs>-20?0:3;}int dr=max(-90,min(90,tr));dr=max(ro-15,min(ro+15,dr));int dp=max(0,min(4,tp));dp=max(pw-1,min(pw+1,dp));printf("%d %d\n",dr,dp);fflush(stdout);}}